import{_ as a,o,c as n,a2 as i}from"./chunks/framework.TWA1q3r6.js";const m=JSON.parse('{"title":"🙌 3-6M · 运动萌芽期","description":"","frontmatter":{"title":"🙌 3-6M · 运动萌芽期"},"headers":[],"relativePath":"stages/3-6m.md","filePath":"stages/3-6m.md"}'),r={name:"stages/3-6m.md"};function e(d,t,l,s,c,p){return o(),n("div",null,[...t[0]||(t[0]=[i('<h1 id="🙌-3-6m-·-运动萌芽期" tabindex="-1">🙌 3-6M · 运动萌芽期 <a class="header-anchor" href="#🙌-3-6m-·-运动萌芽期" aria-label="Permalink to &quot;🙌 3-6M · 运动萌芽期&quot;">​</a></h1><blockquote><p>某天你会发现，小家伙突然翻了个身，然后自己也吓了一跳。</p><p>小手开始有意识地抓住东西 —— 你的手指、一个摇铃、或者爸爸的眼镜。</p></blockquote><hr><h2 id="🎯-发展里程碑" tabindex="-1">🎯 发展里程碑 <a class="header-anchor" href="#🎯-发展里程碑" aria-label="Permalink to &quot;🎯 发展里程碑&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>科学项目</th><th>在做什么</th><th>每天多久</th><th>来源</th></tr></thead><tbody><tr><td>大运动</td><td><strong>辅助翻身 + 延长Tummy Time</strong></td><td>翻身是第一个自主位移 → 空间认知起点</td><td>30-60min累计</td><td>AAP</td></tr><tr><td>精细运动</td><td><strong>抓握练习</strong></td><td>手-眼协调回路建立，全掌抓握向精细抓握过渡</td><td>融入玩耍时间</td><td>CDC</td></tr><tr><td>语言</td><td><strong>Serve &amp; Return 回应式对话</strong></td><td>宝宝咿呀 → 你模仿并延展 → 强化语言回路</td><td>全天候</td><td>Harvard</td></tr><tr><td>感官</td><td><strong>多质地触摸探索</strong></td><td>触觉是最早成熟的感官，多质地促进体感皮层分化</td><td>安全材质即可</td><td>—</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">和上个阶段有什么不同？ 🔄</p><p>0-3M 是被动接收（看、听、被抱），这个阶段开始<strong>主动出击</strong>（翻、抓、&quot;说话&quot;）。你能明显感受到一个小人格正在形成。</p></div><hr><h2 id="🛡️-装备清单" tabindex="-1">🛡️ 装备清单 <a class="header-anchor" href="#🛡️-装备清单" aria-label="Permalink to &quot;🛡️ 装备清单&quot;">​</a></h2><blockquote><p>大件在 <a href="/linyuhan-baby-guide/stages/0-3m.html">0-3M</a> 已经配齐。这个阶段是一些小而美的配件登场。</p></blockquote><h4 id="🦘-婴儿背带-m型腿位-conditional" tabindex="-1">🦘 婴儿背带（M型腿位） <span class="verdict verdict-conditional">Conditional</span> <a class="header-anchor" href="#🦘-婴儿背带-m型腿位-conditional" aria-label="Permalink to &quot;🦘 婴儿背带（M型腿位） Conditional&quot;">​</a></h4><p>如果之前还没入手，现在是最佳时机 —— 3月龄后颈部支撑力增强，背带体验大幅提升。</p><p><strong>选购</strong> Ergobaby Omni 360 / BabyBjörn One ¥500-1,500</p><h4 id="🎵-安全摇铃-布书-conditional" tabindex="-1">🎵 安全摇铃 / 布书 <span class="verdict verdict-conditional">Conditional</span> <a class="header-anchor" href="#🎵-安全摇铃-布书-conditional" aria-label="Permalink to &quot;🎵 安全摇铃 / 布书 Conditional&quot;">​</a></h4><p>配合抓握练习的最佳道具。安全无小零件、手感好、会发出声音就行。</p><p><strong>选购</strong> Manhattan Toy / Sassy / Lamaze，¥30-100</p><h4 id="🦷-出牙咬胶-conditional" tabindex="-1">🦷 出牙咬胶 <span class="verdict verdict-conditional">Conditional</span> <a class="header-anchor" href="#🦷-出牙咬胶-conditional" aria-label="Permalink to &quot;🦷 出牙咬胶 Conditional&quot;">​</a></h4><p>部分宝宝4月龄开始出牙。硅胶或天然橡胶材质，可冷藏后舒缓牙龈不适。</p><p><strong>选购</strong> Sophie la Girafe 🇫🇷 / Comotomo / 可优比，¥30-200</p><h4 id="🏋️-健身架-play-gym-conditional" tabindex="-1">🏋️ 健身架 / Play Gym <span class="verdict verdict-conditional">Conditional</span> <a class="header-anchor" href="#🏋️-健身架-play-gym-conditional" aria-label="Permalink to &quot;🏋️ 健身架 / Play Gym Conditional&quot;">​</a></h4><p>躺着踢、趴着够 —— 多感官刺激的小小健身房。Tummy Time的好搭档，让趴卧时间更有趣。</p><p><strong>选购</strong> IKEA LEKA / Fisher-Price / Lovevery，¥100-800</p><div class="danger custom-block"><p class="custom-block-title">❌ 这些仍然不需要</p><ul><li><strong>学步车</strong> — 现在讨论还太早，但广告已经开始种草了。AAP明确反对，每年数千例急诊</li><li><strong>早教App/屏幕</strong> — AAP建议18月龄前零屏幕。你的脸就是最好的&quot;屏幕&quot;</li></ul></div><hr><h2 id="🌟-这个阶段的小确幸" tabindex="-1">🌟 这个阶段的小确幸 <a class="header-anchor" href="#🌟-这个阶段的小确幸" aria-label="Permalink to &quot;🌟 这个阶段的小确幸&quot;">​</a></h2><p>这时候不需要新买太多东西 —— 0-3M配的夜灯、衣帽架还在发光发热。</p><p>真正的多巴胺来源是：第一次翻身时你们俩的那种惊喜，和每天早上醒来看到宝宝对你笑的那个瞬间。</p><hr><div class="tip custom-block"><p class="custom-block-title">⏰ 采购提醒</p><p>如果之前没赶上大促买安全座椅/婴儿床，研究一下最近的618或双11窗口。同时可以开始关注餐椅 —— 6月龄吃辅食就需要，Stokke Tripp Trapp 大促价差 <strong>¥700+</strong>。详见 <a href="/linyuhan-baby-guide/pricing.html">价格择时</a>。</p></div>',28)])])}const u=a(r,[["render",e]]);export{m as __pageData,u as default};
